/**
 * validators.js — Pure validation functions
 * Each returns { valid: boolean, message: string }
 */

export function validateName(value, fieldName = "Name") {
  if (!value || value.trim().length === 0)
    return { valid: false, message: `${fieldName} is required` };
  if (value.trim().length < 2)
    return { valid: false, message: `${fieldName} must be at least 2 characters` };
  if (!/^[a-zA-Z\s'-]+$/.test(value))
    return { valid: false, message: `${fieldName} can only contain letters` };
  return { valid: true, message: "" };
}

export function validateEmail(email) {
  if (!email || email.trim().length === 0)
    return { valid: false, message: "Email address is required" };
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email))
    return { valid: false, message: "Enter a valid email address" };
  return { valid: true, message: "" };
}

export function validateMobile(mobile) {
  if (!mobile || mobile.trim().length === 0)
    return { valid: false, message: "Mobile number is required" };
  if (!/^\d{10}$/.test(mobile.trim()))
    return { valid: false, message: "Enter a valid 10-digit mobile number" };
  return { valid: true, message: "" };
}

export function validatePassword(password) {
  if (!password || password.length === 0)
    return { valid: false, message: "Password is required" };
  if (password.length < 8)
    return { valid: false, message: "Password must be at least 8 characters" };
  return { valid: true, message: "" };
}

export function validateConfirmPassword(password, confirmPassword) {
  if (!confirmPassword || confirmPassword.length === 0)
    return { valid: false, message: "Please confirm your password" };
  if (password !== confirmPassword)
    return { valid: false, message: "Passwords do not match" };
  return { valid: true, message: "" };
}

/**
 * Password strength scorer
 * Returns { score: 0-4, label: string, color: string }
 */
export function getPasswordStrength(password) {
  if (!password) return { score: 0, label: "", color: "#e0e0e0" };
  let score = 0;
  if (password.length >= 8) score++;
  if (/[A-Z]/.test(password)) score++;
  if (/[0-9]/.test(password)) score++;
  if (/[^A-Za-z0-9]/.test(password)) score++;

  const map = [
    { label: "", color: "#e0e0e0" },
    { label: "Weak", color: "#e53935" },
    { label: "Fair", color: "#fb8c00" },
    { label: "Good", color: "#f9a825" },
    { label: "Strong", color: "#388e3c" },
  ];
  return { score, ...map[score] };
}
